<?php
defined('ABSPATH') || exit;
echo wc_print_notices();
if (!$args['product']->is_purchasable()) { return; }
$product_id = $args['product_id'];
$add_to_cart_text = get_option('skywin_hub_deposit_add_to_cart_text');

if (!isset($add_to_cart_text) || empty($add_to_cart_text)) {
	$add_to_cart_text = $args['product']->single_add_to_cart_text();
}
echo $args['product']->get_short_description();

echo wc_get_stock_html($args['product']);
if ($args['product']->is_in_stock()): ?>
	<form class="cart skywin_hub-deposit-form"
		action="<?php echo esc_url(apply_filters('woocommerce_add_to_cart_form_action', get_permalink())); ?>" method="post"
		enctype='multipart/form-data'>
		<?php do_action( 'woocommerce_before_add_to_cart_button' ); ?> 
		<button type="submit" name="add-to-cart" value="<?php echo esc_attr($args['product_id']); ?>"
			class="single_add_to_cart_button button alt<?php echo esc_attr(wc_wp_theme_get_element_class_name('button') ? ' ' . wc_wp_theme_get_element_class_name('button') : ''); ?>"
			disabled><?php echo esc_html($add_to_cart_text); ?></button>
	</form>

	<style>
		.payment-methods-container{
			width:100%;
		}
	</style>
		<div class="payment-methods-outer-container">
			<div class="payment-methods-container">
				<img alt="" role="presentation" class="payment-method-icon visa light-icon"
					src="data:image/svg+xml;base64,">
				<img alt="" role="presentation" class="payment-method-icon applepay light-icon"
					src="data:image/svg+xml;base64,">
				<img alt="" role="presentation" class="payment-method-icon mastercardwtext light-icon"
					src="data:image/svg+xml;base64,">
				<img alt="" role="presentation" class="payment-method-icon maestrowtext light-icon"
					src="data:image/svg+xml;base64,">
				<img alt="" role="presentation" class="payment-method-icon invoice light-icon"
					src="data:image/svg+xml;base64,">
			</div>
		</div>
	<?php echo do_shortcode(wpautop($args['product']->get_description())); ?>
<?php endif;




